const express = require('express');
const Redis = require('ioredis');
const app = express();
const redis = new Redis();

// Advanced rate limiting middleware with enumeration detection
async function rateLimitMiddleware(req, res, next) {
  const clientIp = req.ip;
  const endpoint = req.route.path;
  const userId = req.params.userId;

  // Track requests per IP
  const ipKey = `ratelimit:ip:${clientIp}`;
  const ipCount = await redis.incr(ipKey);
  await redis.expire(ipKey, 60); // 1 minute window

  // Basic rate limit: 100 requests per minute per IP
  if (ipCount > 100) {
    return res.status(429).json({
      error: 'Rate limit exceeded',
      retryAfter: 60
    });
  }

  // Enumeration detection: Track unique user IDs accessed
  const enumKey = `enum:ip:${clientIp}:${endpoint}`;
  await redis.sadd(enumKey, userId);
  await redis.expire(enumKey, 300); // 5 minute window
  const uniqueUsersAccessed = await redis.scard(enumKey);

  // Alert if accessing more than 20 different user IDs in 5 minutes
  if (uniqueUsersAccessed > 20) {
    // Log security event
    console.warn(`SECURITY: Enumeration detected from ${clientIp} - ${uniqueUsersAccessed} unique users accessed`);

    // Implement progressive throttling
    await redis.setex(`block:${clientIp}`, 3600, 'enumeration'); // Block for 1 hour

    return res.status(403).json({
      error: 'Suspicious activity detected. Access temporarily restricted.',
      contact: 'security@example.com'
    });
  }

  // Check if IP is blocked
  const isBlocked = await redis.get(`block:${clientIp}`);
  if (isBlocked) {
    return res.status(403).json({
      error: 'Access denied due to previous policy violation'
    });
  }

  next();
}

// Apply to user endpoints
app.get('/api/v1/users/:userId', rateLimitMiddleware, async (req, res) => {
  // Authorization check (see MIT-003)
  const requestingUserId = req.user.id;
  const targetUserId = parseInt(req.params.userId);

  if (requestingUserId !== targetUserId && !req.user.isAdmin) {
    return res.status(403).json({ error: 'Unauthorized' });
  }

  // Return user data
  const user = await getUserById(targetUserId);
  res.json(user);
});

