const Hashids = require('hashids');
const hashids = new Hashids('your-salt-here', 16); // Minimum length 16

function encodeId(id) {
  return hashids.encode(id); // 1 -> 'jR3kB7mN9qP2xY5w'
}

function decodeId(hash) {
  const decoded = hashids.decode(hash);
  return decoded.length > 0 ? decoded[0] : null;
}

app.get('/api/v1/orders/:orderId', async (req, res) => {
  const decodedId = decodeId(req.params.orderId);

  if (!decodedId) {
    return res.status(400).json({ error: 'Invalid order ID' });
  }

  // Fetch order using decoded integer ID
  const order = await getOrderById(decodedId);
  res.json(order);
});

const express = require('express');
const jwt = require('jsonwebtoken');
const app = express();

// JWT authentication middleware
function authenticateJWT(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded; // Contains userId, role, etc.
    next();
  } catch (error) {
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
}

// Object-level authorization middleware
function authorizeUserAccess(req, res, next) {
  const requestingUserId = req.user.id;
  const targetUserId = req.params.userId;
  const userRole = req.user.role;

  // Allow access if:
  // 1. User is accessing their own resource
  // 2. User has admin or support role
  if (requestingUserId === targetUserId || ['admin', 'support'].includes(userRole)) {
    return next();
  }

  // Log unauthorized access attempt
  console.warn(`SECURITY: Unauthorized access attempt by user ${requestingUserId} to user ${targetUserId}`);

  return res.status(403).json({
    error: 'Access denied',
    message: 'You do not have permission to access this resource'
  });
}

// Apply both authentication and authorization
app.get('/api/v1/users/:userId', authenticateJWT, authorizeUserAccess, async (req, res) => {
  const user = await getUserById(req.params.userId);

  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  // Filter sensitive fields based on role
  const filteredUser = filterUserData(user, req.user.role);
  res.json(filteredUser);
});

// More complex authorization for resources with ownership
app.get('/api/v1/orders/:orderId', authenticateJWT, async (req, res) => {
  const order = await getOrderById(req.params.orderId);

  if (!order) {
    return res.status(404).json({ error: 'Order not found' });
  }

  // Verify the order belongs to the requesting user
  if (order.userId !== req.user.id && !req.user.isAdmin) {
    console.warn(`SECURITY: User ${req.user.id} attempted to access order ${req.params.orderId} belonging to user ${order.userId}`);
    return res.status(403).json({ error: 'Access denied' });
  }

  res.json(order);
});

// Authorization for related resources (e.g., user's documents)
app.get('/api/v1/users/:userId/documents/:documentId', authenticateJWT, async (req, res) => {
  const document = await getDocumentById(req.params.documentId);

  if (!document) {
    return res.status(404).json({ error: 'Document not found' });
  }

  // Verify document belongs to the user in the URL
  if (document.userId !== req.params.userId) {
    return res.status(404).json({ error: 'Document not found' }); // Don't reveal existence
  }

  // Verify requesting user can access this user's documents
  if (req.user.id !== req.params.userId && !req.user.isAdmin) {
    return res.status(403).json({ error: 'Access denied' });
  }

  res.json(document);
});

function filterUserData(user, role) {
  // Admins see all fields
  if (role === 'admin') {
    return user;
  }

  // Regular users see limited fields
  return {
    id: user.id,
    name: user.name,
    email: user.email,
    createdAt: user.createdAt
    // Exclude: phone, address, SSN, payment methods, etc.
  };
}
